// CustomerMapper.java - Interfaz Mapper
package com.paymentchange.customer.mapper;

import com.paymentchange.customer.dto.request.CustomerRequest;
import com.paymentchange.customer.dto.response.CustomerResponse;
import com.paymentchange.customer.entities.Customer;
import org.mapstruct.Mapper;
import org.mapstruct.Mapping;
import java.util.List;

@Mapper(componentModel = "spring")
public interface CustomerMapper {

    /**
     * Convierte CustomerRequest (DTO entrada) a Customer (Entidad)
     */
    @Mapping(target = "id", ignore = true)  // ID se genera automático
    @Mapping(target = "createdAt", ignore = true)
    @Mapping(target = "updatedAt", ignore = true)
    @Mapping(target = "status", constant = "ACTIVE")  // Valor por defecto
    Customer toEntity(CustomerRequest request);

    /**
     * Convierte Customer (Entidad) a CustomerResponse (DTO salida)
     */
    CustomerResponse toResponse(Customer entity);

    /**
     * Convierte lista de Customer a lista de CustomerResponse
     * MapStruct usa toResponse() para cada elemento automáticamente
     */
    List<CustomerResponse> toResponseList(List<Customer> entities);

    /**
     * Actualizar entidad existente con datos de request
     * Útil para operaciones PUT
     */
    @Mapping(target = "id", ignore = true)
    @Mapping(target = "createdAt", ignore = true)
    void updateEntityFromRequest(CustomerRequest request, 
                                 @MappingTarget Customer entity);
}

// CustomerMapperImpl.java - Generado automáticamente
// target/generated-sources/annotations/.../CustomerMapperImpl.java
@Component
public class CustomerMapperImpl implements CustomerMapper {

    @Override
    public Customer toEntity(CustomerRequest request) {
        if (request == null) {
            return null;
        }
        Customer customer = new Customer();
        customer.setName(request.getName());
        customer.setPhoneNumber(request.getPhoneNumber());
        customer.setEmail(request.getEmail());
        customer.setProductIds(request.getProductIds());
        customer.setStatus("ACTIVE");
        return customer;
    }

    @Override
    public CustomerResponse toResponse(Customer entity) {
        if (entity == null) {
            return null;
        }
        CustomerResponse response = new CustomerResponse();
        response.setId(entity.getId());
        response.setName(entity.getName());
        response.setPhoneNumber(entity.getPhoneNumber());
        response.setEmail(entity.getEmail());
        response.setStatus(entity.getStatus());
        response.setProductIds(entity.getProductIds());
        return response;
    }

    // ... otros métodos generados
}

// CustomerService.java - Refactorizado con DTOs
@Service
public class CustomerService {

    @Autowired
    private CustomerRepository customerRepository;

    @Autowired
    private CustomerMapper customerMapper;  // Inyectar mapper

    public List<CustomerResponse> findAll() {
        List<Customer> customers = customerRepository.findAll();
        return customerMapper.toResponseList(customers);
    }

    public CustomerResponse findById(Long id) {
        Customer customer = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));
        return customerMapper.toResponse(customer);
    }

    public CustomerResponse create(CustomerRequest request) {
        // Validar datos de request
        validateCustomerRequest(request);

        // Convertir Request a Entity
        Customer customer = customerMapper.toEntity(request);

        // Guardar en BD
        Customer saved = customerRepository.save(customer);

        // Convertir Entity a Response
        return customerMapper.toResponse(saved);
    }

    public CustomerResponse update(Long id, CustomerRequest request) {
        // Buscar customer existente
        Customer existing = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));

        // Actualizar campos desde request
        customerMapper.updateEntityFromRequest(request, existing);

        // Guardar cambios
        Customer updated = customerRepository.save(existing);

        // Retornar response
        return customerMapper.toResponse(updated);
    }

    public void delete(Long id) {
        Customer customer = customerRepository.findById(id)
            .orElseThrow(() -> new NotFoundException(
                "Customer with ID " + id + " not found"
            ));
        customerRepository.delete(customer);
    }

    private void validateCustomerRequest(CustomerRequest request) {
        if (request.getName() == null || request.getName().isEmpty()) {
            throw new IllegalArgumentException("Name is required");
        }
        // ... más validaciones
    }
}

